args.sparql:
SELECT ?victor ?victorLabel WHERE {
  ?battle rdfs:label 'Battle of Stirling Bridge'@en ;
          wdt:P31 wd:Q811387 .
  ?battle wdt:P1347 ?victor .
  ?victor rdfs:label ?victorLabel .
  FILTER (LANG(?victorLabel) = 'en')
}

SELECT ?victor ?victorLabel WHERE {
  ?battle rdfs:label 'Battle of Stirling Bridge (1297)'@en ;
          wdt:P31 wd:Q811387 ;
          wdt:P1347 ?victor .
  ?victor rdfs:label ?victorLabel .
  FILTER (LANG(?victorLabel) = 'en')
}

